+where
+    I: IntoIterator<Item = S>,
+    S: AsRef<OsStr>,
+{
+    args.into_iter().any(|arg| {
+        let text = arg.as_ref().to_string_lossy();
+        text == "--format" || text.starts_with("--format=")
+    })
+}
